type Context = Record<string, unknown>;

const TOKEN = /(?:\s+)|(?:\d+(?:\.\d+)?)|(?:[A-Za-z_][A-Za-z0-9_]*)|(?:==|!=|<=|>=|&&|\|\||[()+\-*/%<>=!.,])/g;

function tokenize(expr: string): string[] {
  const tokens = expr.match(TOKEN)?.filter(Boolean) ?? [];
  const joined = tokens.join("");
  if (joined.replace(/\s+/g, "") !== expr.replace(/\s+/g, "")) {
    throw new Error(`Invalid token in expression: ${expr}`);
  }
  return tokens.filter((t) => !/^\s+$/.test(t));
}

export function evaluateTemplateExpression(input: string, context: Context): unknown {
  const match = input.match(/^\s*\{\{\s*([\s\S]+?)\s*\}\}\s*$/);
  if (!match) return input;

  const expr = match[1];
  const tokens = tokenize(expr);

  // Minimal recursive-descent parser for arithmetic expressions
  let i = 0;

  function peek() {
    return tokens[i];
  }

  function consume(expected?: string) {
    const t = tokens[i];
    if (expected && t !== expected) throw new Error(`Expected "${expected}"`);
    i++;
    return t;
  }

  function parsePrimary(): unknown {
    const t = peek();
    if (!t) throw new Error("Unexpected end of expression");

    if (/^\d/.test(t)) {
      consume();
      return Number(t);
    }

    if (/^[A-Za-z_]/.test(t)) {
      consume();
      if (!(t in context)) throw new Error(`Unknown variable: ${t}`);
      return context[t];
    }

    if (t === "(") {
      consume("(");
      const value = parseAddSub();
      consume(")");
      return value;
    }

    throw new Error(`Unexpected token: ${t}`);
