    const value = this.parseOr();
    if (this.i !== this.tokens.length) {
      throw new Error(`Unexpected token: ${this.tokens[this.i]}`);
    }
    return value;
  }

  private peek() {
    return this.tokens[this.i];
  }

  private consume(expected?: string) {
    const t = this.tokens[this.i++];
    if (expected && t !== expected) throw new Error(`Expected ${expected}, got ${t}`);
    return t;
  }

  private parseOr() {
    let left = this.parseAnd();
    while (this.peek() === '||') {
      this.consume('||');
      left = left || this.parseAnd();
    }
    return left;
  }

  private parseAnd() {
    let left = this.parseEquality();
    while (this.peek() === '&&') {
      this.consume('&&');
      left = left && this.parseEquality();
    }
    return left;
  }

  private parseEquality() {
    let left = this.parseRelational();
    while (this.peek() === '==' || this.peek() === '!=') {
      const op = this.consume();
      const right = this.parseRelational();
      left = op === '==' ? left == right : left != right;
    }
    return left;
  }

  private parseRelational() {
    let left = this.parseAdditive();
    while (['<', '>', '<=', '>='].includes(this.peek())) {
      const op = this.consume();
      const right = this.parseAdditive();
      switch (op) {
        case '<': left = left < right; break;
        case '>': left = left > right; break;
        case '<=': left = left <= right; break;
        case '>=': left = left >= right; break;
      }
    }
    return left;
  }

  private parseAdditive() {
    let left = this.parseMultiplicative();
    while (this.peek() === '+' || this.peek() === '-') {
      const op = this.consume();
      const right = this.parseMultiplicative();
      left = op === '+' ? left + right : left - right;
    }
    return left;
  }

  private parseMultiplicative() {
    let left = this.parseUnary();
    while (['*', '/', '%'].includes(this.peek())) {
      const op = this.consume();
      const right = this.parseUnary();
      switch (op) {
        case '*': left = left * right; break;
        case '/': left = left / right; break;
        case '%': left = left % right; break;
      }
