export function evaluateTemplateFormula(input: string, context: Context): unknown {
  const match = input.match(/^\{\{\s*(.+?)\s*\}\}$/);
  if (!match) return input;

  const expr = match[1].trim();

  // Very small safe evaluator for: identifier, number, and binary ops
  const tokens = expr.match(/[A-Za-z_][A-Za-z0-9_]*|\d+(?:\.\d+)?|[+\-*/()]/g);
  if (!tokens || tokens.join('') !== expr.replace(/\s+/g, '')) {
    throw new Error(`Invalid expression: ${expr}`);
  }

  const values = tokens.map((t) => {
    if (/^\d/.test(t)) return Number(t);
    if (t in OPS || t === '(' || t === ')') return t;
    if (!(t in context)) throw new Error(`Unknown variable: ${t}`);
    const v = context[t];
    if (typeof v !== 'number') throw new Error(`Variable must be numeric: ${t}`);
    return v;
  });

  // Shunting-yard to RPN
  const output: (number | string)[] = [];
  const stack: string[] = [];
  const prec: Record<string, number> = { '+': 1, '-': 1, '*': 2, '/': 2 };

  for (const tok of values) {
    if (typeof tok === 'number') {
      output.push(tok);
    } else if (tok in OPS) {
      while (stack.length && stack[stack.length - 1] in OPS && prec[stack[stack.length - 1]] >= prec[tok]) {
        output.push(stack.pop()!);
      }
      stack.push(tok);
    } else if (tok === '(') {
      stack.push(tok);
    } else if (tok === ')') {
      while (stack.length && stack[stack.length - 1] !== '(') output.push(stack.pop()!);
      if (stack.pop() !== '(') throw new Error('Mismatched parentheses');
    }
  }
  while (stack.length) {
    const op = stack.pop()!;
    if (op === '(') throw new Error('Mismatched parentheses');
    output.push(op);
  }

  // Evaluate RPN
  const s: number[] = [];
  for (const tok of output) {
    if (typeof tok === 'number') s.push(tok);
    else {
      const b = s.pop();
      const a = s.pop();
      if (a === undefined || b === undefined) throw new Error('Invalid expression');
      s.push(OPS[tok](a, b));
    }
  }

  if (s.length !== 1) throw new Error('Invalid expression');
  return s[0];
}

