      while (i < input.length && /[0-9.]/.test(input[i])) i++;
      const value = Number(input.slice(start, i));
      if (!Number.isFinite(value)) throw new Error("Invalid number");
      return { type: "literal", value };
    }

    if (/[A-Za-z_$]/.test(ch)) {
      const start = i;
      i++;
      while (i < input.length && /[A-Za-z0-9_$\.]/.test(input[i])) i++;
      return { type: "identifier", name: input.slice(start, i) };
    }

    throw new Error(`Unexpected token at ${i}`);
  }

  function parseUnary() {
    skipWs();
    if (input[i] === "+") {
      i++;
      return { type: "unary", op: "+", expr: parseUnary() };
    }
    if (input[i] === "-") {
      i++;
      return { type: "unary", op: "-", expr: parseUnary() };
    }
    return parsePrimary();
  }

  function parseMulDiv() {
    let node = parseUnary();
    while (true) {
      skipWs();
      const op = input[i];
      if (op !== "*" && op !== "/" && op !== "%") break;
      i++;
      node = { type: "binary", op, left: node, right: parseUnary() };
    }
    return node;
  }

  function parseAddSub() {
    let node = parseMulDiv();
    while (true) {
      skipWs();
      const op = input[i];
      if (op !== "+" && op !== "-") break;
      i++;
      node = { type: "binary", op, left: node, right: parseMulDiv() };
    }
